using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.UnitTests;public class EhrServiceTests_GetPatientEhrRecords_WithSeedPatient_ShouldReturnResult : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {    "AuthService",    "EhrService"    };    [SkippableFact]    public async Task GetPatientEhrRecords_WithSeedPatient_ShouldReturnResult()    {    await AuthenticateAsAdminAsync(EhrClient);    var response = await GetWithRetryAsync(EhrClient, ApiEndpoints.Ehr.PatientRecords(TestSeedData.PatientUserId));        Assert.Equal(HttpStatusCode.OK, response.StatusCode);    var json = await ReadJsonResponseAsync(response);    Assert.Equal(JsonValueKind.Array, json.ValueKind);    }}